// mm/src/api/checkout.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';

/**
 * Create a Stripe Checkout Session (server-side).
 *
 * Your backend should expose:
 *   POST {API_BASE}/api/checkout
 *
 * Expected response:
 *   { url: "https://checkout.stripe.com/..." }
 *
 * NOTE:
 * - In local dev, you can set "proxy" in package.json to your backend (recommended),
 *   and leave REACT_APP_API_BASE_URL empty.
 * - In prod, set REACT_APP_API_BASE_URL to your API domain.
 */
export async function createCheckoutSession(payload) {
  const url = `${API_BASE}/api/checkout`;

  const resp = await axios.post(url, payload, {
    headers: { 'Content-Type': 'application/json' },
    // keep consistent with your app pattern (use if backend sets cookies/session)
    withCredentials: true,
  });

  const checkoutUrl = resp?.data?.url;
  if (!checkoutUrl) {
    throw new Error('Checkout session did not return a redirect URL.');
  }

  return resp.data;
}

/**
 * Optional: verify a checkout session after Stripe redirect
 * Backend route suggestion:
 *   GET {API_BASE}/api/checkout/verify?session_id=...
 * Response:
 *   { paid: true, orderId: "...", downloads: [...] }
 */
export async function verifyCheckoutSession(sessionId) {
  if (!sessionId) throw new Error('Missing session_id');

  const url = `${API_BASE}/api/checkout/verify`;
  const resp = await axios.get(url, {
    params: { session_id: sessionId },
    withCredentials: true,
  });

  return resp.data;
}
